"""
Parameterized generator for GH1214_airflow_64120.

Source PR:    https://github.com/apache/airflow/pull/64120
Source Issue: N/A

Seed varies: renames 'as_json' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1214_airflow_64120'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1214_airflow_64120'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('as_json', 'as_json' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1214_airflow_64120',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'apache/airflow',
                "pr_number": 64120,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/apache/airflow/pull/64120",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'task-sdk/src/airflow/sdk/definitions/connection.py': '#\n# Licensed to the Apache Software Foundation (ASF) under one\n# or more contributor license agreements.  See the NOTICE file\n# distributed with this work for additional information\n# regarding copyright ownership.  The ASF licenses this file\n# to you under the Apache License, Version 2.0 (the\n# "License"); you may not use this file except in compliance\n# with the License.  You may obtain a copy of the License at\n#\n#   http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing,\n# software distributed under the License is distributed on an\n# "AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\n# KIND, either express or implied.  See the License for the\n# specific language governing permissions and limitations\n# under the License.\nfrom __future__ import annotations\n\nimport json\nimport logging\nfrom json import JSONDecodeError\nfrom typing import Any, overload\nfrom urllib.parse import parse_qsl, quote, unquote, urlencode, urlsplit\n\nimport attrs\n\nfrom airflow.sdk.exceptions import AirflowException, AirflowNotFoundException, AirflowRuntimeError, ErrorType\nfrom airflow.sdk.providers_manager_runtime import ProvidersManagerTaskRuntime\n\nlog = logging.getLogger(__name__)\n\n\ndef _parse_netloc_to_hostname(uri_parts):\n    """\n    Parse a URI string to get the correct Hostname.\n\n    ``urlparse(...).hostname`` or ``urlsplit(...).hostname`` returns value into the lowercase in most cases,\n    there are some exclusion exists for specific cases such as https://bugs.python.org/issue32323\n    In case if expected to get a path as part of hostname path,\n    then default behavior ``urlparse``/``urlsplit`` is unexpected.\n    """\n    hostname = unquote(uri_parts.hostname or "")\n    if "/" in hostname:\n        hostname = uri_parts.netloc\n        if "@" in hostname:\n            hostname = hostname.rsplit("@", 1)[1]\n        if ":" in hostname:\n            hostname = hostname.split(":", 1)[0]\n        hostname = unquote(hostname)\n    return hostname\n\n\ndef _prune_dict(val: Any, mode="strict"):\n    """\n    Given dict ``val``, returns new dict based on ``val`` with all empty elements removed.\n\n    What constitutes "empty" is controlled by the ``mode`` parameter.  If mode is \'strict\'\n    then only ``None`` elements will be removed.  If mode is ``truthy``, then element ``x``\n    will be removed if ``bool(x) is False``.\n    """\n    if mode == "strict":\n        is_empty = lambda x: x is None\n    elif mode == "truthy":\n        is_empty = lambda x: not bool(x)\n    else:\n        raise ValueError("allowable values for `mode` include \'truthy\' and \'strict\'")\n\n    if isinstance(val, dict):\n        new_dict = {}\n        for k, v in val.items():\n            if is_empty(v):\n                continue\n            if isinstance(v, (list, dict)):\n                new_val = _prune_dict(v, mode=mode)\n                if not is_empty(new_val):\n                    new_dict[k] = new_val\n            else:\n                new_dict[k] = v\n        return new_dict\n    if isinstance(val, list):\n        new_list = []\n        for v in val:\n            if is_empty(v):\n                continue\n            if isinstance(v, (list, dict)):\n                new_val = _prune_dict(v, mode=mode)\n                if not is_empty(new_val):\n                    new_list.append(new_val)\n            else:\n                new_list.append(v)\n        return new_list\n    return val\n\n\n@attrs.define(slots=False)\nclass Connection:\n    """\n    A connection to an external data source.\n\n    :param conn_id: The connection ID.\n    :param conn_type: The connection type.\n    :param description: The connection description.\n    :param host: The host.\n    :param login: The login.\n    :param password: The password.\n    :param schema: The schema.\n    :param port: The port number.\n    :param extra: Extra metadata. Non-standard data such as private/SSH keys can be saved here. JSON\n        encoded object.\n    :param uri: URI address describing connection parameters.\n    """\n\n    conn_id: str\n    conn_type: str | None = None\n    description: str | None = None\n    host: str | None = None\n    schema: str | None = None\n    login: str | None = None\n    password: str | None = None\n    port: int | None = None\n    extra: str | None = None\n\n    EXTRA_KEY = "__extra__"\n\n    @overload\n    def __init__(self, *, conn_id: str, uri: str) -> None: ...\n\n    @overload\n    def __init__(\n        self,\n        *,\n        conn_id: str,\n        conn_type: str | None = None,\n        description: str | None = None,\n        host: str | None = None,\n        schema: str | None = None,\n        login: str | None = None,\n        password: str | None = None,\n        port: int | None = None,\n        extra: str | None = None,\n    ) -> None: ...\n\n    def __init__(self, *, conn_id: str, uri: str | None = None, **kwargs) -> None:\n        if uri is not None and kwargs:\n            raise AirflowException(\n                "You must create an object using the URI or individual values "\n                "(conn_type, host, login, password, schema, port or extra). "\n                "You can\'t mix these two ways to create this object."\n            )\n        if uri is None:\n            self.__attrs_init__(conn_id=conn_id, **kwargs)  # type: ignore[attr-defined]\n        else:\n            self.__dict__.update(self.from_uri(uri, conn_id=conn_id).to_dict(validate=False))\n\n    def get_uri(self) -> str:\n        """Generate and return connection in URI format."""\n        from urllib.parse import parse_qsl\n\n        if self.conn_type and "_" in self.conn_type:\n            log.warning(\n                "Connection schemes (type: %s) shall not contain \'_\' according to RFC3986.",\n                self.conn_type,\n            )\n        if self.conn_type:\n            uri = f"{self.conn_type.lower().replace(\'_\', \'-\')}://"\n        else:\n            uri = "//"\n        host_to_use: str | None\n        if self.host and "://" in self.host:\n            protocol, host = self.host.split("://", 1)\n            # If the protocol in host matches the connection type, don\'t add it again\n            if protocol == self.conn_type:\n                host_to_use = self.host\n                protocol_to_add = None\n            else:\n                # Different protocol, add it to the URI\n                host_to_use = host\n                protocol_to_add = protocol\n        else:\n            host_to_use = self.host\n            protocol_to_add = None\n\n        if protocol_to_add:\n            uri += f"{protocol_to_add}://"\n\n        authority_block = ""\n        if self.login is not None:\n            authority_block += quote(self.login, safe="")\n        if self.password is not None:\n            authority_block += ":" + quote(self.password, safe="")\n        if authority_block > "":\n            authority_block += "@"\n            uri += authority_block\n\n        host_block = ""\n        if host_to_use:\n            host_block += quote(host_to_use, safe="")\n        if self.port:\n            if host_block == "" and authority_block == "":\n                host_block += f"@:{self.port}"\n            else:\n                host_block += f":{self.port}"\n        if self.schema:\n            host_block += f"/{quote(self.schema, safe=\'\')}"\n        uri += host_block\n\n        if self.extra:\n            try:\n                extra_dejson = self.extra_dejson\n                query: str | None = urlencode(extra_dejson)\n            except TypeError:\n                query = None\n            if query and extra_dejson == dict(parse_qsl(query, keep_blank_values=True)):\n                uri += ("?" if self.schema else "/?") + query\n            else:\n                uri += ("?" if self.schema else "/?") + urlencode({self.EXTRA_KEY: self.extra})\n\n        return uri\n\n    def get_hook(self, *, hook_params=None):\n        """Return hook based on conn_type."""\n        from airflow.sdk._shared.module_loading import import_string\n\n        hook = ProvidersManagerTaskRuntime().hooks.get(self.conn_type, None)\n\n        if hook is None:\n            raise AirflowException(f\'Unknown hook type "{self.conn_type}"\')\n        try:\n            hook_class = import_string(hook.hook_class_name)\n        except ImportError:\n            log.error(\n                "Could not import %s when discovering %s %s",\n                hook.hook_class_name,\n                hook.hook_name,\n                hook.package_name,\n            )\n            raise\n        if hook_params is None:\n            hook_params = {}\n        return hook_class(**{hook.connection_id_attribute_name: self.conn_id}, **hook_params)\n\n    @classmethod\n    def _handle_connection_error(cls, e: AirflowRuntimeError, conn_id: str) -> None:\n        """Handle connection retrieval errors."""\n        if e.error.error == ErrorType.CONNECTION_NOT_FOUND:\n            raise AirflowNotFoundException(f"The conn_id `{conn_id}` isn\'t defined") from None\n        raise\n\n    @classmethod\n    def get(cls, conn_id: str) -> Any:\n        from airflow.sdk.execution_time.context import _get_connection\n\n        try:\n            return _get_connection(conn_id)\n        except AirflowRuntimeError as e:\n            cls._handle_connection_error(e, conn_id)\n\n    @classmethod\n    async def async_get(cls, conn_id: str) -> Any:\n        from airflow.sdk.execution_time.context import _async_get_connection\n\n        try:\n            return await _async_get_connection(conn_id)\n        except AirflowRuntimeError as e:\n            cls._handle_connection_error(e, conn_id)\n\n    @property\n    def extra_dejson(self) -> dict:\n        """Returns the extra property by deserializing json."""\n        from airflow.sdk.log import mask_secret\n\n        extra = {}\n        if self.extra:\n            try:\n                extra = json.loads(self.extra)\n            except JSONDecodeError:\n                log.exception("Failed to deserialize extra property `extra`, returning empty dictionary")\n            else:\n                mask_secret(extra)\n\n        return extra\n\n    def get_extra_dejson(self) -> dict:\n        """Deserialize extra property to JSON."""\n        import warnings\n\n        warnings.warn(\n            "`get_extra_dejson` is deprecated and will be removed in a future release. ",\n            DeprecationWarning,\n            stacklevel=2,\n        )\n        return self.extra_dejson\n\n    def to_dict(self, *, prune_empty: bool = False, validate: bool = True) -> dict[str, Any]:\n        """\n        Convert Connection to json-serializable dictionary.\n\n        :param prune_empty: Whether or not remove empty values.\n        :param validate: Validate dictionary is JSON-serializable\n\n        :meta private:\n        """\n        conn: dict[str, Any] = {\n            "conn_id": self.conn_id,\n            "conn_type": self.conn_type,\n            "description": self.description,\n            "host": self.host,\n            "login": self.login,\n            "password": self.password,\n            "schema": self.schema,\n            "port": self.port,\n        }\n        if prune_empty:\n            conn = _prune_dict(val=conn, mode="strict")\n        if (extra := self.extra_dejson) or not prune_empty:\n            conn["extra"] = extra\n\n        if validate:\n            json.dumps(conn)\n        return conn\n\n    @classmethod\n    def from_json(cls, value, conn_id=None) -> Connection:\n        kwargs = json.loads(value)\n        extra = kwargs.pop("extra", None)\n        if extra:\n            kwargs["extra"] = extra if isinstance(extra, str) else json.dumps(extra)\n        conn_type = kwargs.pop("conn_type", None)\n        if conn_type:\n            kwargs["conn_type"] = cls._normalize_conn_type(conn_type)\n        port = kwargs.pop("port", None)\n        if port:\n            try:\n                kwargs["port"] = int(port)\n            except ValueError:\n                raise ValueError(f"Expected integer value for `port`, but got {port!r} instead.")\n        return cls(conn_id=conn_id, **kwargs)\n\n    def as_json(self) -> str:\n        """Convert Connection to JSON-string object."""\n        conn_repr = self.to_dict(prune_empty=True, validate=False)\n        conn_repr.pop("conn_id", None)\n        return json.dumps(conn_repr)\n\n    @classmethod\n    def from_uri(cls, uri: str, conn_id: str) -> Connection:\n        """\n        Create a Connection from a URI string.\n\n        :param uri: URI string to parse\n        :param conn_id: Connection ID to assign to the connection\n        :return: Connection object\n        """\n        schemes_count_in_uri = uri.count("://")\n        if schemes_count_in_uri > 2:\n            raise AirflowException(f"Invalid connection string: {uri}.")\n        host_with_protocol = schemes_count_in_uri == 2\n        uri_parts = urlsplit(uri)\n        conn_type = uri_parts.scheme\n        normalized_conn_type = cls._normalize_conn_type(conn_type)\n        rest_of_the_url = uri.replace(f"{conn_type}://", ("" if host_with_protocol else "//"))\n        if host_with_protocol:\n            uri_splits = rest_of_the_url.split("://", 1)\n            if "@" in uri_splits[0] or ":" in uri_splits[0]:\n                raise AirflowException(f"Invalid connection string: {uri}.")\n        uri_parts = urlsplit(rest_of_the_url)\n        protocol = uri_parts.scheme if host_with_protocol else None\n        host = _parse_netloc_to_hostname(uri_parts)\n        parsed_host = cls._create_host(protocol, host)\n        quoted_schema = uri_parts.path[1:]\n        schema = unquote(quoted_schema) if quoted_schema else quoted_schema\n        login = unquote(uri_parts.username) if uri_parts.username else uri_parts.username\n        password = unquote(uri_parts.password) if uri_parts.password else uri_parts.password\n        port = uri_parts.port\n        extra = None\n        if uri_parts.query:\n            query = dict(parse_qsl(uri_parts.query, keep_blank_values=True))\n            if cls.EXTRA_KEY in query:\n                extra = query[cls.EXTRA_KEY]\n            else:\n                extra = json.dumps(query)\n\n        return cls(\n            conn_id=conn_id,\n            conn_type=normalized_conn_type,\n            host=parsed_host,\n            schema=schema,\n            login=login,\n            password=password,\n            port=port,\n            extra=extra,\n        )\n\n    @staticmethod\n    def _create_host(protocol, host) -> str | None:\n        """Return the connection host with the protocol."""\n        if not host:\n            return host\n        if protocol:\n            return f"{protocol}://{host}"\n        return host\n\n    @staticmethod\n    def _normalize_conn_type(conn_type):\n        if conn_type == "postgresql":\n            conn_type = "postgres"\n        elif "-" in conn_type:\n            conn_type = conn_type.replace("-", "_")\n        return conn_type\n',
            'task-sdk/tests/task_sdk/definitions/test_connection.py': '#\n# Licensed to the Apache Software Foundation (ASF) under one\n# or more contributor license agreements.  See the NOTICE file\n# distributed with this work for additional information\n# regarding copyright ownership.  The ASF licenses this file\n# to you under the Apache License, Version 2.0 (the\n# "License"); you may not use this file except in compliance\n# with the License.  You may obtain a copy of the License at\n#\n#   http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing,\n# software distributed under the License is distributed on an\n# "AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\n# KIND, either express or implied.  See the License for the\n# specific language governing permissions and limitations\n# under the License.\nfrom __future__ import annotations\n\nimport json\nfrom unittest import mock\nfrom urllib.parse import urlparse\n\nimport pytest\n\nfrom airflow.sdk import Connection\nfrom airflow.sdk.configuration import initialize_secrets_backends\nfrom airflow.sdk.exceptions import AirflowException, AirflowNotFoundException, ErrorType\nfrom airflow.sdk.execution_time.comms import ConnectionResult, ErrorResponse\nfrom airflow.sdk.execution_time.secrets import DEFAULT_SECRETS_SEARCH_PATH_WORKERS\n\nfrom tests_common.test_utils.config import conf_vars\n\n\nclass TestConnections:\n    @pytest.fixture\n    def mock_providers_manager(self):\n        """Mock the ProvidersManager to return predefined hooks."""\n        with mock.patch("airflow.sdk.definitions.connection.ProvidersManagerTaskRuntime") as mock_manager:\n            yield mock_manager\n\n    @mock.patch("airflow.sdk._shared.module_loading.import_string")\n    def test_get_hook(self, mock_import_string, mock_providers_manager):\n        """Test that get_hook returns the correct hook instance."""\n\n        mock_hook_class = mock.MagicMock()\n        mock_hook_class.return_value = "mock_hook_instance"\n        mock_import_string.return_value = mock_hook_class\n\n        mock_hook = mock.MagicMock()\n        mock_hook.hook_class_name = "airflow.providers.mysql.hooks.mysql.MySqlHook"\n        mock_hook.connection_id_attribute_name = "conn_id"\n\n        mock_providers_manager.return_value.hooks = {"mysql": mock_hook}\n\n        conn = Connection(\n            conn_id="test_conn",\n            conn_type="mysql",\n        )\n\n        hook_instance = conn.get_hook(hook_params={"param1": "value1"})\n\n        mock_import_string.assert_called_once_with("airflow.providers.mysql.hooks.mysql.MySqlHook")\n\n        mock_hook_class.assert_called_once_with(conn_id="test_conn", param1="value1")\n\n        assert hook_instance == "mock_hook_instance"\n\n    def test_get_hook_invalid_type(self, mock_providers_manager):\n        """Test that get_hook raises AirflowException for unknown hook type."""\n        mock_providers_manager.return_value.hooks = {}\n\n        conn = Connection(\n            conn_id="test_conn",\n            conn_type="unknown_type",\n        )\n\n        with pytest.raises(AirflowException, match=\'Unknown hook type "unknown_type"\'):\n            conn.get_hook()\n\n    def test_get_uri(self):\n        """Test that get_uri generates the correct URI based on connection attributes."""\n\n        conn = Connection(\n            conn_id="test_conn",\n            conn_type="mysql",\n            host="localhost",\n            login="user",\n            password="password",\n            schema="test_schema",\n            port=3306,\n            extra=None,\n        )\n\n        uri = conn.get_uri()\n        parsed_uri = urlparse(uri)\n\n        assert uri == "mysql://user:password@localhost:3306/test_schema"\n        assert parsed_uri.scheme == "mysql"\n        assert parsed_uri.hostname == "localhost"\n        assert parsed_uri.username == "user"\n        assert parsed_uri.password == "password"\n        assert parsed_uri.port == 3306\n        assert parsed_uri.path.lstrip("/") == "test_schema"\n\n    def test_conn_get(self, mock_supervisor_comms):\n        conn_result = ConnectionResult(conn_id="mysql_conn", conn_type="mysql", host="mysql", port=3306)\n        mock_supervisor_comms.send.return_value = conn_result\n\n        conn = Connection.get(conn_id="mysql_conn")\n        assert conn is not None\n        assert isinstance(conn, Connection)\n        assert conn == Connection(\n            conn_id="mysql_conn",\n            conn_type="mysql",\n            description=None,\n            host="mysql",\n            schema=None,\n            login=None,\n            password=None,\n            port=3306,\n            extra=None,\n        )\n\n    def test_conn_get_not_found(self, mock_supervisor_comms):\n        error_response = ErrorResponse(error=ErrorType.CONNECTION_NOT_FOUND)\n        mock_supervisor_comms.send.return_value = error_response\n\n        with pytest.raises(AirflowNotFoundException, match="The conn_id `mysql_conn` isn\'t defined"):\n            _ = Connection.get(conn_id="mysql_conn")\n\n    def test_to_dict(self):\n        """Test that to_dict returns correct dictionary representation."""\n        connection = Connection(\n            conn_id="test_conn",\n            conn_type="http",\n            login="user",\n            password="pass",\n            host="https://api.example.com/",\n            port=443,\n            schema="https",\n            extra=\'{"timeout": 30, "verify": false}\',\n        )\n\n        result = connection.to_dict()\n\n        assert result == {\n            "conn_id": "test_conn",\n            "conn_type": "http",\n            "description": None,\n            "host": "https://api.example.com/",\n            "login": "user",\n            "password": "pass",\n            "schema": "https",\n            "port": 443,\n            "extra": {"timeout": 30, "verify": False},\n        }\n\n    def test_as_json(self):\n        """Test that as_json returns valid JSON string without conn_id."""\n        connection = Connection(\n            conn_id="test_conn",\n            conn_type="postgres",\n            host="localhost",\n            port=5432,\n        )\n\n        json_str = connection.as_json()\n        result = json.loads(json_str)\n\n        # Should not include conn_id\n        assert "conn_id" not in result\n        assert result["conn_type"] == "postgres"\n        assert result["host"] == "localhost"\n        assert result["port"] == 5432\n\n    def test_from_json(self):\n        """Test that from_json creates Connection with type normalization."""\n        json_data = {\n            "conn_type": "postgresql",\n            "host": "localhost",\n            "port": "5432",\n        }\n        expected_id = "postgres"\n        connection = Connection.from_json(json.dumps(json_data), conn_id="test_conn")\n\n        assert connection.conn_id == "test_conn"\n        assert connection.conn_type == expected_id\n        assert connection.host == "localhost"\n        assert connection.port == 5432\n\n    def test_from_json_without_conn_type(self):\n        """Test that from_json works without conn_type (backward compatibility with AF 2)."""\n        json_data = {\n            "host": "mydb.example.com",\n            "port": "5432",\n            "login": "admin",\n            "password": "secret",\n            "schema": "production",\n        }\n        connection = Connection.from_json(json.dumps(json_data), conn_id="test_conn")\n\n        assert connection.conn_id == "test_conn"\n        assert connection.conn_type is None\n        assert connection.host == "mydb.example.com"\n        assert connection.port == 5432\n        assert connection.login == "admin"\n        assert connection.password == "secret"\n        assert connection.schema == "production"\n\n    def test_extra_dejson_property(self):\n        """Test that extra_dejson property correctly deserializes JSON extra field."""\n        connection = Connection(\n            conn_id="test_conn",\n            conn_type="http",\n            extra=\'{"timeout": 30, "verify": false, "retries": 3}\',\n        )\n\n        result = connection.extra_dejson\n        assert result == {"timeout": 30, "verify": False, "retries": 3}\n\n        connection.extra = None\n        assert connection.extra_dejson == {}\n\n        connection.extra = \'{"auth": {"type": "oauth"}, "headers": {"User-Agent": "Airflow"}}\'\n        assert connection.extra_dejson == {"auth": {"type": "oauth"}, "headers": {"User-Agent": "Airflow"}}\n\n\nclass TestConnectionsFromSecrets:\n    def test_get_connection_secrets_backend(self, mock_supervisor_comms, tmp_path):\n        """Tests getting a connection from secrets backend."""\n        path = tmp_path / "conn.env"\n        path.write_text("CONN_A=mysql://host_a")\n\n        with conf_vars(\n            {\n                (\n                    "workers",\n                    "secrets_backend",\n                ): "airflow.secrets.local_filesystem.LocalFilesystemBackend",\n                ("workers", "secrets_backend_kwargs"): f\'{{"connections_file_path": "{path}"}}\',\n            }\n        ):\n            retrieved_conn = Connection.get(conn_id="CONN_A")\n            assert retrieved_conn is not None\n            assert retrieved_conn.conn_id == "CONN_A"\n\n    @mock.patch("airflow.secrets.environment_variables.EnvironmentVariablesBackend.get_connection")\n    def test_get_connection_env_var(self, mock_env_get, mock_supervisor_comms):\n        """Tests getting a connection from environment variable."""\n        mock_env_get.return_value = Connection(conn_id="something", conn_type="some-type")  # return None\n        Connection.get("something")\n        mock_env_get.assert_called_once_with(conn_id="something")\n\n    @conf_vars(\n        {\n            ("workers", "secrets_backend"): "airflow.secrets.local_filesystem.LocalFilesystemBackend",\n            ("workers", "secrets_backend_kwargs"): \'{"connections_file_path": "/files/conn.json"}\',\n        }\n    )\n    @mock.patch("airflow.secrets.local_filesystem.LocalFilesystemBackend.get_connection")\n    @mock.patch("airflow.secrets.environment_variables.EnvironmentVariablesBackend.get_connection")\n    def test_backend_fallback_to_env_var(self, mock_get_connection, mock_env_get, mock_supervisor_comms):\n        """Tests if connection retrieval falls back to environment variable backend if not found in secrets backend."""\n        mock_get_connection.return_value = None\n        mock_env_get.return_value = Connection(conn_id="something", conn_type="some-type")\n\n        backends = initialize_secrets_backends(DEFAULT_SECRETS_SEARCH_PATH_WORKERS)\n        assert len(backends) == 3\n        backend_classes = [backend.__class__.__name__ for backend in backends]\n        assert "LocalFilesystemBackend" in backend_classes\n\n        conn = Connection.get(conn_id="something")\n        # mock_env is only called when LocalFilesystemBackend doesn\'t have it\n        mock_env_get.assert_called()\n        assert conn == Connection(conn_id="something", conn_type="some-type")\n\n\nclass TestConnectionFromUri:\n    """Test the Connection.from_uri() classmethod."""\n\n    def test_from_uri_basic(self):\n        """Test basic URI parsing."""\n        uri = "postgres://user:pass@host:5432/db"\n        conn = Connection.from_uri(uri, conn_id="test_conn")\n\n        assert conn.conn_id == "test_conn"\n        assert conn.conn_type == "postgres"\n        assert conn.host == "host"\n        assert conn.login == "user"\n        assert conn.password == "pass"\n        assert conn.port == 5432\n        assert conn.schema == "db"\n        assert conn.extra is None\n\n    def test_from_uri_with_query_params(self):\n        """Test URI parsing with query parameters."""\n        uri = "mysql://user:pass@host:3306/db?charset=utf8&timeout=30"\n        conn = Connection.from_uri(uri, conn_id="test_conn")\n\n        assert conn.conn_id == "test_conn"\n        assert conn.conn_type == "mysql"\n        assert conn.host == "host"\n        assert conn.login == "user"\n        assert conn.password == "pass"\n        assert conn.port == 3306\n        assert conn.schema == "db"\n        # Extra should be JSON string with query params\n        extra_dict = json.loads(conn.extra)\n        assert extra_dict == {"charset": "utf8", "timeout": "30"}\n\n    def test_from_uri_with_extra_key(self):\n        """Test URI parsing with __extra__ query parameter."""\n        extra_value = json.dumps({"ssl_mode": "require", "connect_timeout": 10})\n        uri = f"postgres://user:pass@host:5432/db?__extra__={extra_value}"\n        conn = Connection.from_uri(uri, conn_id="test_conn")\n\n        assert conn.conn_id == "test_conn"\n        assert conn.conn_type == "postgres"\n        assert conn.extra == extra_value\n\n    def test_from_uri_with_protocol_in_host(self):\n        """Test URI parsing with protocol in host (double ://)."""\n        uri = "http://https://example.com:8080/path"\n        conn = Connection.from_uri(uri, conn_id="test_conn")\n\n        assert conn.conn_id == "test_conn"\n        assert conn.conn_type == "http"\n        assert conn.host == "https://example.com"\n        assert conn.port == 8080\n        assert conn.schema == "path"\n\n    def test_from_uri_encoded_credentials(self):\n        """Test URI parsing with URL-encoded credentials."""\n        uri = "postgres://user%40domain:pass%21word@host:5432/db"\n        conn = Connection.from_uri(uri, conn_id="test_conn")\n\n        assert conn.conn_id == "test_conn"\n        assert conn.conn_type == "postgres"\n        assert conn.login == "user@domain"\n        assert conn.password == "pass!word"\n\n    def test_from_uri_minimal(self):\n        """Test URI parsing with minimal information."""\n        uri = "redis://"\n        conn = Connection.from_uri(uri, conn_id="test_conn")\n\n        assert conn.conn_id == "test_conn"\n        assert conn.conn_type == "redis"\n        assert conn.host == ""  # urlsplit returns empty string, not None for minimal URI\n        assert conn.login is None\n        assert conn.password is None\n        assert conn.port is None\n        assert conn.schema == ""\n\n    def test_from_uri_conn_type_normalization(self):\n        """Test that connection types are normalized."""\n        # postgresql -> postgres\n        uri = "postgresql://user:pass@host:5432/db"\n        conn = Connection.from_uri(uri, conn_id="test_conn")\n        assert conn.conn_type == "postgres"\n\n        # hyphen to underscore\n        uri = "google-cloud-platform://user:pass@host/db"\n        conn = Connection.from_uri(uri, conn_id="test_conn")\n        assert conn.conn_type == "google_cloud_platform"\n\n    def test_from_uri_too_many_schemes_error(self):\n        """Test that too many schemes in URI raises an error."""\n        uri = "http://https://ftp://example.com"\n        with pytest.raises(AirflowException, match="Invalid connection string"):\n            Connection.from_uri(uri, conn_id="test_conn")\n\n    def test_from_uri_invalid_protocol_host_error(self):\n        """Test that invalid protocol host raises an error."""\n        uri = "http://user@host://example.com"\n        with pytest.raises(AirflowException, match="Invalid connection string"):\n            Connection.from_uri(uri, conn_id="test_conn")\n\n    def test_connection_constructor_with_uri(self):\n        """Test Connection(uri=..., conn_id=...) constructor form."""\n        conn = Connection(conn_id="test_conn", uri="postgres://user:pass@host:5432/db")\n\n        assert conn.conn_id == "test_conn"\n        assert conn.conn_type == "postgres"\n        assert conn.host == "host"\n        assert conn.login == "user"\n        assert conn.password == "pass"\n        assert conn.port == 5432\n        assert conn.schema == "db"\n        # uri should not exist as an attribute (it\'s init-only)\n        assert not hasattr(conn, "uri")\n\n    def test_from_uri_roundtrip(self):\n        """Test that from_uri and get_uri are inverse operations."""\n        original_uri = "postgres://user:pass@host:5432/db?param1=value1&param2=value2"\n        conn = Connection.from_uri(original_uri, conn_id="test_conn")\n        roundtrip_uri = conn.get_uri()\n\n        # Parse both URIs to compare (order of query params might differ)\n        conn_from_original = Connection.from_uri(original_uri, conn_id="test")\n        conn_from_roundtrip = Connection.from_uri(roundtrip_uri, conn_id="test")\n\n        assert conn_from_original.conn_type == conn_from_roundtrip.conn_type\n        assert conn_from_original.host == conn_from_roundtrip.host\n        assert conn_from_original.login == conn_from_roundtrip.login\n        assert conn_from_original.password == conn_from_roundtrip.password\n        assert conn_from_original.port == conn_from_roundtrip.port\n        assert conn_from_original.schema == conn_from_roundtrip.schema\n        # Check extra content is equivalent (JSON order might differ)\n        if conn_from_original.extra:\n            original_extra = json.loads(conn_from_original.extra)\n            roundtrip_extra = json.loads(conn_from_roundtrip.extra)\n            assert original_extra == roundtrip_extra\n',
        }
